-- Dev-only repeatable ESCO skill catalog seed.
-- Loaded via %dev Flyway location: classpath:db/dev
-- Source CSV: .tmp/esco_skills_en.csv (ESCO export format)

VALUES (
    'd3000000-0000-0000-0000-000000000001',
    'ESCO Skills (EN)',
    'ESCO skills catalog in English for local development and testing.',
    '{"0":"None","1":"Aware","2":"Beginner","3":"Practitioner","4":"Advanced","5":"Expert"}'::jsonb,
    'ESCO v1.2.1'
)
ON CONFLICT (id) DO UPDATE
SET name = EXCLUDED.name,
    description = EXCLUDED.description,
    level_scale = EXCLUDED.level_scale,
    source = EXCLUDED.source,
    updated_at = now();

DELETE FROM skills.skill_definition WHERE catalog_id = 'd3000000-0000-0000-0000-000000000001';



























